def categorize_bisaya_subgroups(region, religion=None):
    categories = {
        'Sabah': {'religion': 'Muslim', 'locations': ['Beaufort', 'Kuala Penyu', 'Sipitang', 'Labuan']},
        'Sarawak': {'religion': 'Christian', 'locations': ['Limbang River', 'Lawas']},
        'Brunei': {'religion': ['Muslim', 'Non-Muslim'], 'classifications': ['Dusun', 'Jati Dusun'], 'locations': ['Belait', 'Temburong', 'Tutong']}
    }
    return categories.get(region, 'Region not found')

# Example usage:
print(categorize_bisaya_subgroups('Sabah'))
print(categorize_bisaya_subgroups('Sarawak', 'Christian'))
